import React, { useState, useEffect, useCallback } from "react";
import { useNavigate } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import {
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
} from "../components/ui/card";
import { Button } from "../components/ui/button";
import { Input } from "../components/ui/input";
import { Calendar } from "../components/ui/calendar";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "../components/ui/popover";
import { CalendarIcon, X, Zap, Clock, Calculator } from "lucide-react";
import { format } from "date-fns";
import { cn } from "../lib/utils";
import { authService } from "../services/api";
import api from "../services/api";

// Types
interface User {
  id: string;
  email: string;
  username: string;
  is_active: boolean;
  created_at: string;
}

interface Appliance {
  id: string;
  name: string;
  category: string;
  wattage: number;
  room_name?: string;
}

interface UsagePopupData {
  appliance: Appliance;
  date: Date;
  hoursUsed: string;
}

interface BillBreakdown {
  total_units_consumed: number;
  fixed_charge_cost: number;
  total_bill_estimate: number;
  slab_breakdown: Array<{
    slab: string;
    units: number;
    rate: number;
    cost: number;
  }>;
  appliance_consumption_list: Array<{
    name: string;
    monthly_kwh: number;
    cost_apportioned: number;
    highest_slab_rate: number;
  }>;
  ai_suggestions?: string[];
}

const LogUsage: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [appliances, setAppliances] = useState<Appliance[]>([]);
  const [selectedAppliance, setSelectedAppliance] = useState<Appliance | null>(null);
  const [usageType, setUsageType] = useState<string>("");
  const [hoursValue, setHoursValue] = useState<string>("");
  const [selectedDate, setSelectedDate] = useState<Date>(new Date());
  const [billData, setBillData] = useState<BillBreakdown | null>(null);
  const [calculating, setCalculating] = useState(false);
  const [notification, setNotification] = useState<{ type: 'success' | 'error'; message: string } | null>(null);
  const navigate = useNavigate();

  // Initialize user and load appliances
  useEffect(() => {
    const fetchUserAndAppliances = async () => {
      try {
        const token = localStorage.getItem("access_token");
        if (!token) {
          navigate("/login");
          return;
        }
        const userData = await authService.getCurrentUser();
        setUser(userData);
        await loadAppliances();
      } catch (error) {
        console.error("Failed to fetch user:", error);
        navigate("/login");
      } finally {
        setLoading(false);
      }
    };
    fetchUserAndAppliances();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [navigate]);

  // Load appliances from all rooms
  const loadAppliances = async () => {
    try {
      const roomsResponse = await api.get('/energy/rooms');
      const allAppliances: Appliance[] = [];

      for (const room of roomsResponse.data) {
        try {
          const appliancesResponse = await api.get(`/energy/rooms/${room.id}/appliances`);
          const roomAppliances = appliancesResponse.data.map((appliance: any) => ({
            ...appliance,
            room_name: room.name
          }));
          allAppliances.push(...roomAppliances);
        } catch (error) {
          console.error(`Failed to load appliances for room ${room.name}:`, error);
        }
      }

      setAppliances(allAppliances);
    } catch (error) {
      console.error("Failed to load appliances:", error);
      showNotification('error', 'Failed to load appliances');
    }
  };

  // Show notification
  const showNotification = useCallback((type: 'success' | 'error', message: string) => {
    setNotification({ type, message });
    setTimeout(() => setNotification(null), 5000);
  }, []);

  // Handle usage logging
  const handleLogUsage = async () => {
    if (!selectedAppliance || !usageType || !hoursValue) {
      showNotification('error', 'Please fill all fields');
      return;
    }

    try {
      const response = await api.post('/energy/usage-log', {
        appliance_id: selectedAppliance.id,
        usage_type: usageType,
        hours_value: parseFloat(hoursValue),
        log_date: selectedDate.toISOString().split('T')[0] // Send date in YYYY-MM-DD format
      });

      showNotification('success', `✅ Usage logged: ${response.data.calculated_monthly_kwh.toFixed(1)} kWh/month`);

      // Reset form
      setSelectedAppliance(null);
      setUsageType("");
      setHoursValue("");
      setSelectedDate(new Date());

    } catch (error: any) {
      console.error("Failed to log usage:", error);
      showNotification('error', `Failed to log usage: ${error.response?.data?.detail || 'Unknown error'}`);
    }
  };

  // Calculate bill and get AI suggestions
  const handleCalculateBill = async () => {
    setCalculating(true);
    try {
      const response = await api.post('/energy/calculate-bill');
      setBillData(response.data);
      showNotification('success', '💡 Bill calculated with AI recommendations!');
    } catch (error: any) {
      console.error("Failed to calculate bill:", error);
      showNotification('error', `Failed to calculate bill: ${error.response?.data?.detail || 'Unknown error'}`);
    } finally {
      setCalculating(false);
    }
  };

  const goToDashboard = useCallback(() => {
    navigate("/dashboard");
  }, [navigate]);

  const handleLogout = useCallback(() => {
    authService.logout();
    navigate("/login");
  }, [navigate]);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <div className="w-8 h-8 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
          <p className="text-muted-foreground">Loading...</p>
        </div>
      </div>
    );
  }

  if (!user) return null;

  return (
    <div className="min-h-screen bg-gradient-to-br from-green-50 via-blue-50 to-indigo-100 relative overflow-hidden">
      {/* Animated Background */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div className="absolute -top-4 -left-4 w-72 h-72 bg-green-200 rounded-full mix-blend-multiply filter blur-xl opacity-30 animate-pulse"></div>
        <div className="absolute top-1/4 -right-4 w-72 h-72 bg-blue-200 rounded-full mix-blend-multiply filter blur-xl opacity-30 animate-pulse animation-delay-2000"></div>
        <div className="absolute -bottom-8 left-1/3 w-72 h-72 bg-indigo-200 rounded-full mix-blend-multiply filter blur-xl opacity-30 animate-pulse animation-delay-4000"></div>
      </div>

      {/* Notification */}
      <AnimatePresence>
        {notification && (
          <motion.div
            initial={{ opacity: 0, y: -50 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -50 }}
            className={`fixed top-4 right-4 z-50 p-4 rounded-lg shadow-lg ${
              notification.type === 'success' 
                ? 'bg-green-500 text-white' 
                : 'bg-red-500 text-white'
            }`}
          >
            {notification.message}
          </motion.div>
        )}
      </AnimatePresence>

      {/* Navigation */}
      <nav className="bg-white/90 backdrop-blur-md shadow-lg border-b border-green-100">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
            <div 
              className="flex items-center space-x-3 cursor-pointer hover:opacity-80 transition-opacity"
              onClick={goToDashboard}
            >
              <div className="w-8 h-8 bg-gradient-to-br from-green-500 to-blue-600 rounded-lg flex items-center justify-center">
                <span className="text-white font-bold text-lg">⚡</span>
              </div>
              <h1 className="text-2xl font-bold bg-gradient-to-r from-green-600 to-blue-600 bg-clip-text text-transparent">
                WattWise
              </h1>
            </div>
            <div className="flex items-center space-x-4">
              <span className="text-sm text-gray-700 font-medium">
                Welcome, {user.username}
              </span>
              <Button variant="outline" onClick={goToDashboard} className="border-blue-200 text-blue-700 hover:bg-blue-50">
                Back to Dashboard
              </Button>
              <Button variant="outline" onClick={handleLogout} className="border-green-200 text-green-700 hover:bg-green-50">
                Logout
              </Button>
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto py-6 sm:px-6 lg:px-8">
        <div className="px-4 py-6 sm:px-0 space-y-6">
          {/* Header */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5 }}
          >
            <Card className="bg-gradient-to-br from-white/80 to-green-50 backdrop-blur-lg border-green-200 shadow-xl">
              <CardHeader>
                <CardTitle className="text-3xl font-bold bg-gradient-to-r from-green-600 to-blue-600 bg-clip-text text-transparent">
                  ⚡ Log Usage & Calculate Bills
                </CardTitle>
                <CardDescription className="text-lg text-gray-600">
                  Track your appliance usage and get AI-powered savings recommendations
                </CardDescription>
              </CardHeader>
            </Card>
          </motion.div>

          {/* Usage Logging Form */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {/* Log Usage Card */}
            <Card className="bg-white/90 backdrop-blur-lg border-gray-200 shadow-xl">
              <CardHeader>
                <CardTitle className="text-xl font-bold text-gray-800">📝 Log Appliance Usage</CardTitle>
                <CardDescription>
                  Select an appliance and log how you used it
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                {/* Appliance Selection */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Select Appliance</label>
                  <select
                    value={selectedAppliance?.id || ""}
                    onChange={(e) => {
                      const appliance = appliances.find(a => a.id === e.target.value);
                      setSelectedAppliance(appliance || null);
                    }}
                    className="w-full rounded-md border-gray-300 bg-white px-3 py-2 text-sm focus:border-blue-500 focus:ring-blue-500"
                  >
                    <option value="">Choose an appliance</option>
                    {appliances.map((appliance) => (
                      <option key={appliance.id} value={appliance.id}>
                        {appliance.name} ({appliance.room_name}) - {appliance.wattage}W
                      </option>
                    ))}
                  </select>
                </div>

                {/* Usage Type Selection */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Usage Type</label>
                  <div className="space-y-2">
                    <label className="flex items-center">
                      <input
                        type="radio"
                        name="usage_type"
                        value="daily"
                        checked={usageType === "daily"}
                        onChange={(e) => setUsageType(e.target.value)}
                        className="mr-2"
                      />
                      <span className="text-sm">Daily Log - Used for X hours today</span>
                    </label>
                    <label className="flex items-center">
                      <input
                        type="radio"
                        name="usage_type"
                        value="weekly"
                        checked={usageType === "weekly"}
                        onChange={(e) => setUsageType(e.target.value)}
                        className="mr-2"
                      />
                      <span className="text-sm">Weekly Average - Y hours per week</span>
                    </label>
                    <label className="flex items-center">
                      <input
                        type="radio"
                        name="usage_type"
                        value="monthly"
                        checked={usageType === "monthly"}
                        onChange={(e) => setUsageType(e.target.value)}
                        className="mr-2"
                      />
                      <span className="text-sm">Monthly Estimate - Z kWh this month</span>
                    </label>
                  </div>
                </div>

                {/* Date Selection */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Date
                  </label>
                  <Popover>
                    <PopoverTrigger asChild>
                      <Button
                        variant="outline"
                        className={cn(
                          "w-full justify-start text-left font-normal",
                          !selectedDate && "text-muted-foreground"
                        )}
                      >
                        <CalendarIcon className="mr-2 h-4 w-4" />
                        {selectedDate ? format(selectedDate, "PPP") : <span>Pick a date</span>}
                      </Button>
                    </PopoverTrigger>
                    <PopoverContent className="w-auto p-0" align="start">
                      <Calendar
                        mode="single"
                        selected={selectedDate}
                        onSelect={(date: Date | undefined) => date && setSelectedDate(date)}
                        initialFocus
                      />
                    </PopoverContent>
                  </Popover>
                </div>

                {/* Hours/kWh Input */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    {usageType === "daily" && "Hours used today"}
                    {usageType === "weekly" && "Average hours per week"}
                    {usageType === "monthly" && "Total kWh this month"}
                    {!usageType && "Value"}
                  </label>
                  <Input
                    type="number"
                    placeholder={
                      usageType === "daily" ? "e.g., 8" :
                      usageType === "weekly" ? "e.g., 56" :
                      usageType === "monthly" ? "e.g., 150" :
                      "Enter value"
                    }
                    value={hoursValue}
                    onChange={(e) => setHoursValue(e.target.value)}
                    className="border-gray-300 focus:border-blue-500 focus:ring-blue-500"
                    min="0"
                    step="0.1"
                  />
                </div>

                <Button
                  onClick={handleLogUsage}
                  disabled={!selectedAppliance || !usageType || !hoursValue}
                  className="w-full bg-green-600 text-white hover:bg-green-700 disabled:opacity-50"
                >
                  📊 Log Usage
                </Button>
              </CardContent>
            </Card>

            {/* Calculate Bill Card */}
            <Card className="bg-white/90 backdrop-blur-lg border-gray-200 shadow-xl">
              <CardHeader>
                <CardTitle className="text-xl font-bold text-gray-800">💰 Calculate Monthly Bill</CardTitle>
                <CardDescription>
                  Get detailed breakdown and AI-powered savings tips
                </CardDescription>
              </CardHeader>
              <CardContent>
                <Button
                  onClick={handleCalculateBill}
                  disabled={calculating}
                  className="w-full bg-blue-600 text-white hover:bg-blue-700 disabled:opacity-50 py-3"
                >
                  {calculating ? (
                    <>
                      <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin mr-2"></div>
                      Calculating...
                    </>
                  ) : (
                    <>🤖 Calculate Bill with AI Suggestions</>
                  )}
                </Button>

                {/* Quick Stats */}
                {appliances.length > 0 && (
                  <div className="mt-4 p-4 bg-gray-50 rounded-lg">
                    <h4 className="font-semibold text-gray-700 mb-2">Your Appliances</h4>
                    <p className="text-sm text-gray-600">
                      {appliances.length} appliances across your rooms
                    </p>
                    <p className="text-sm text-gray-600">
                      Total capacity: {appliances.reduce((sum, a) => sum + a.wattage, 0)}W
                    </p>
                  </div>
                )}
              </CardContent>
            </Card>
          </div>

          {/* Bill Breakdown Results */}
          {billData && (
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.5 }}
              className="space-y-6"
            >
              {/* Bill Summary */}
              <Card className="bg-gradient-to-br from-white/90 to-green-50 backdrop-blur-lg border-green-200 shadow-xl">
                <CardHeader>
                  <CardTitle className="text-2xl font-bold bg-gradient-to-r from-green-600 to-blue-600 bg-clip-text text-transparent">
                    💡 Your Monthly Bill Breakdown
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <div className="text-center p-4 bg-blue-50 rounded-lg">
                      <p className="text-sm text-gray-600">Total Consumption</p>
                      <p className="text-2xl font-bold text-blue-600">{billData.total_units_consumed} kWh</p>
                    </div>
                    <div className="text-center p-4 bg-green-50 rounded-lg">
                      <p className="text-sm text-gray-600">Energy Cost</p>
                      <p className="text-2xl font-bold text-green-600">₹{(billData.total_bill_estimate - billData.fixed_charge_cost).toFixed(2)}</p>
                    </div>
                    <div className="text-center p-4 bg-orange-50 rounded-lg">
                      <p className="text-sm text-gray-600">Total Bill</p>
                      <p className="text-2xl font-bold text-orange-600">₹{billData.total_bill_estimate.toFixed(2)}</p>
                    </div>
                  </div>
                </CardContent>
              </Card>

              {/* Slab Breakdown */}
              {billData.slab_breakdown.length > 0 && (
                <Card className="bg-white/90 backdrop-blur-lg border-gray-200 shadow-xl">
                  <CardHeader>
                    <CardTitle className="text-xl font-bold text-gray-800">📊 Tariff Slab Breakdown</CardTitle>
                  </CardHeader>
                  <CardContent>
                    <div className="space-y-3">
                      {billData.slab_breakdown.map((slab, index) => (
                        <div key={index} className="flex justify-between items-center p-3 bg-gray-50 rounded-lg">
                          <div>
                            <span className="font-medium text-gray-800">{slab.slab} units</span>
                            <span className="text-sm text-gray-600 ml-2">@ ₹{slab.rate}/unit</span>
                          </div>
                          <div className="text-right">
                            <span className="text-sm text-gray-600">{slab.units} kWh</span>
                            <span className="block font-semibold text-blue-600">₹{slab.cost.toFixed(2)}</span>
                          </div>
                        </div>
                      ))}
                    </div>
                  </CardContent>
                </Card>
              )}

              {/* Appliance Consumption */}
              {billData.appliance_consumption_list.length > 0 && (
                <Card className="bg-white/90 backdrop-blur-lg border-gray-200 shadow-xl">
                  <CardHeader>
                    <CardTitle className="text-xl font-bold text-gray-800">⚡ Appliance-wise Consumption</CardTitle>
                  </CardHeader>
                  <CardContent>
                    <div className="space-y-3">
                      {billData.appliance_consumption_list.map((appliance, index) => (
                        <div key={index} className="flex justify-between items-center p-3 bg-gray-50 rounded-lg">
                          <div>
                            <span className="font-medium text-gray-800">{appliance.name}</span>
                            <span className="text-sm text-gray-600 ml-2">({appliance.monthly_kwh} kWh/month)</span>
                          </div>
                          <div className="text-right">
                            <span className="text-sm text-red-600">Max rate: ₹{appliance.highest_slab_rate}/unit</span>
                            <span className="block font-semibold text-blue-600">₹{appliance.cost_apportioned.toFixed(2)}</span>
                          </div>
                        </div>
                      ))}
                    </div>
                  </CardContent>
                </Card>
              )}

              {/* AI Suggestions */}
              {billData.ai_suggestions && billData.ai_suggestions.length > 0 && (
                <Card className="bg-gradient-to-br from-purple-50 to-pink-50 backdrop-blur-lg border-purple-200 shadow-xl">
                  <CardHeader>
                    <CardTitle className="text-xl font-bold bg-gradient-to-r from-purple-600 to-pink-600 bg-clip-text text-transparent">
                      🤖 AI-Powered Savings Recommendations
                    </CardTitle>
                  </CardHeader>
                  <CardContent>
                    <div className="space-y-4">
                      {billData.ai_suggestions.map((suggestion, index) => (
                        <div key={index} className="flex items-start space-x-3 p-4 bg-white/70 rounded-lg border border-purple-100">
                          <div className="w-8 h-8 bg-gradient-to-br from-purple-400 to-pink-500 rounded-full flex items-center justify-center flex-shrink-0">
                            <span className="text-white font-bold text-sm">{index + 1}</span>
                          </div>
                          <p className="text-gray-800 leading-relaxed">{suggestion}</p>
                        </div>
                      ))}
                    </div>
                  </CardContent>
                </Card>
              )}
            </motion.div>
          )}
        </div>
      </main>
    </div>
  );
};

export default LogUsage;
